const city = query.city || 'Rome';
const geo = await helpers.httpRequest({ method: 'GET', url: 'https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(city) + '&count=1&language=en' });
if (!geo.results || geo.results.length === 0) return 'City not found: ' + city;
const lat = geo.results[0].latitude;
const lon = geo.results[0].longitude;
const name = geo.results[0].name;
const weather = await helpers.httpRequest({ method: 'GET', url: 'https://api.open-meteo.com/v1/forecast?latitude=' + lat + '&longitude=' + lon + '&current_weather=true&daily=temperature_2m_max,temperature_2m_min,precipitation_probability_max,windspeed_10m_max&timezone=auto&forecast_days=3' });
const current = weather.current_weather;
const daily = weather.daily;
const labels = ['today', 'tomorrow', 'in two days'];
let response = `${name}: ${current.temperature}C, wind ${current.windspeed} km/h\n`;
for (let i = 0; i < 3; i += 1) {
  response += `${labels[i]}: ${daily.temperature_2m_min[i]}-${daily.temperature_2m_max[i]}C, ${daily.precipitation_probability_max[i]}% rain, wind ${daily.windspeed_10m_max[i]} km/h\n`;
}
return response.trim();
